public class MavibotBackend extends AbstractIdentityBackend { private static final String DATA_TREE = "kerby-data" ; private static final String DATABASE_NAME = "kerby-data.db" ; private static final Logger LOG = LoggerFactory . getLogger ( MavibotBackend . class ) ; private RecordManager rm ; private BTree < String , KrbIdentity > database ; public MavibotBackend ( File location ) throws Exception { String dbPath = location . getAbsolutePath ( ) ; LOG . info ( "Initializing the mavibot backend" ) ; if ( ! location . exists ( ) && ! location . mkdirs ( ) ) { throw new KrbException ( "Can't create location file" ) ; } if ( location . isDirectory ( ) ) { dbPath += File . separator + DATABASE_NAME ; } rm = new RecordManager ( dbPath ) ; if ( rm . getManagedTrees ( ) . contains ( DATA_TREE ) ) { database = rm . getManagedTree ( DATA_TREE ) ; } else { PersistedBTreeConfiguration < String , KrbIdentity > config = new PersistedBTreeConfiguration < String , KrbIdentity > ( ) ; config . setAllowDuplicates ( false ) ; config . setBtreeType ( BTreeTypeEnum . PERSISTED ) ; config . setFilePath ( dbPath ) ; config . setKeySerializer ( StringSerializer . INSTANCE ) ; config . setName ( DATA_TREE ) ; config . setValueSerializer ( KrbIdentitySerializer . INSTANCE ) ; database = BTreeFactory . createPersistedBTree ( config ) ; rm . manage ( database ) ; } } @ Override protected Iterable < String > doGetIdentities ( ) throws KrbException { List < String > keys = new ArrayList < String > ( ) ; KeyCursor < String > cursor = null ; try { cursor = database . browseKeys ( ) ; while ( cursor . hasNext ( ) ) { keys . add ( cursor . next ( ) ) ; } } catch ( Exception e ) { throw new KrbException ( "Errors occurred while fetching the principals" , e ) ; } finally { if ( cursor != null ) { cursor . close ( ) ; } } return keys ; } @ Override protected KrbIdentity doGetIdentity ( String principalName ) throws KrbException { try { return database . get ( principalName ) ; } catch ( KeyNotFoundException e ) { LOG . debug ( "Identity {} doesn't exist" , principalName ) ; return null ; } catch ( IOException e ) { throw new KrbException ( "Failed to get the identity " + principalName ) ; } } @ Override protected synchronized KrbIdentity doAddIdentity ( KrbIdentity identity ) throws KrbException { String p = identity . getPrincipalName ( ) ; try { if ( database . hasKey ( p ) ) { throw new KrbException ( "Identity already exists " + p ) ; } return database . insert ( p , identity ) ; } catch ( KeyNotFoundException e ) { throw new KrbException ( "No such identity exists " + p ) ; } catch ( IOException e ) { throw new KrbException ( "Failed to add the identity " + p ) ; } } @ Override protected synchronized KrbIdentity doUpdateIdentity ( KrbIdentity identity ) throws KrbException { String p = identity . getPrincipalName ( ) ; try { if ( ! database . hasKey ( p ) ) { throw new KrbException ( "No identity found with the principal " + p ) ; } database . delete ( p ) ; return database . insert ( p , identity ) ; } catch ( Exception e ) { throw new KrbException ( "Failed to update the identity " + p ) ; } } @ Override protected void doDeleteIdentity ( String principalName ) throws KrbException { try { Tuple < String , KrbIdentity > t = database . delete ( principalName ) ; if ( t == null ) { throw new KrbException ( "Not existing, identity = " + principalName ) ; } } catch ( IOException e ) { throw new KrbException ( "Failed to delete the identity " + principalName ) ; } } @ Override protected void doStop ( ) throws KrbException { try { rm . close ( ) ; } catch ( IOException e ) { throw new KrbException ( "Failed to close the database" , e ) ; } } }